import { useCallback, useEffect, useRef, useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { toast } from "@/utils/toast";
import NavigationBar from "@/components/NavigationBar";
import Button from "@/components/Button";
import { useUser } from "@/hooks/useUser";
import { useTask } from "@/hooks/useTask";
import { useLoading } from "@/hooks/useLoading";
import { useAutoFocus } from "@/hooks/useAutoFocus";
import { TaskId } from "@/types/task";
import type { UserGeoLocation } from "@sitin/api-proto/gen/archat_api/user_api";
import { goBack } from "@/utils/navigation";
import { getGeocodeInfo } from "@/utils/locationUtils";
import { bpTrack } from "@/tracking";
import { EventName } from "@/tracking/events";
import Input from "@/pages/Onboarding/Input";

const DEFAULT_HINT = "This will help us to get you matched with people who are nearby";
const ERROR_HINT = "Please enter a valid ZIP code format";

function isValidZipCode(value: string): boolean {
  return /^\d{5}$/.test(value);
}

// 解析 CSV 文本为 ZipCodeEntry 数组（轻量实现）
function parseCsv(csvText: string) {
  const lines = csvText.split("\n");
  return lines.slice(1).reduce<{ usZipcode: string; location: string }[]>((acc, line) => {
    const trimmed = line.trim();
    if (!trimmed) return acc;
    const firstComma = trimmed.indexOf(",");
    if (firstComma === -1) return acc;
    acc.push({
      usZipcode: trimmed.slice(0, firstComma),
      location: trimmed.slice(firstComma + 1),
    });
    return acc;
  }, []);
}

export default function EditZipCode() {
  const location = useLocation();
  const navigate = useNavigate();
  const state = location.state as { lat?: number; lng?: number } | null;

  const { userInfo, updateProfile } = useUser();
  const { finishTask } = useTask();
  const { showLoading, hideLoading } = useLoading();

  const inputRef = useRef<HTMLInputElement>(null);

  const [zipcode, setZipcode] = useState(userInfo?.geoLocation?.zipCode ?? "");
  const [csvData, setCsvData] = useState<{ usZipcode: string; location: string }[]>([]);
  const [hint, setHint] = useState(DEFAULT_HINT);
  const [error, setError] = useState(false);

  // 无经纬度参数时自动 focus 输入框
  const hasLatLng = Boolean(state?.lat && state?.lng);
  useAutoFocus(inputRef, { enabled: !hasLatLng, defer: "raf" });

  // 埋点：页面展示
  useEffect(() => {
    bpTrack(EventName.pwa_onboarding_location_page_show);
    bpTrack(EventName.pwa_conv_location_page_show); // 转化埋点
  }, []);

  // 加载 CSV 数据
  useEffect(() => {
    const fetchCsv = async () => {
      try {
        const response = await fetch("/csv/us_zipcode.csv");
        const csvText = await response.text();
        const parsed = parseCsv(csvText);
        setCsvData(parsed);

        // 如果已有 zipcode，尝试匹配显示城市信息
        if (zipcode) {
          const match = parsed.find((row) => row.usZipcode === zipcode);
          if (match) setHint(match.location);
        }
      } catch (e) {
        console.error("Failed to load zipcode CSV:", e);
      }
    };

    fetchCsv();
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const handleSave = useCallback(
    async (province: string, city: string, zipCode: string) => {
      try {
        const geoLocation: UserGeoLocation = {
          province,
          city,
          zipCode,
        };
        await updateProfile({ location: geoLocation });
        await finishTask(TaskId.LocationPermission);

        // 埋点：位置确认（只传 zipcode，与 react-haven 保持一致）
        bpTrack(EventName.pwa_onboarding_location_page_confirm, { zipcode: zipCode });
        bpTrack(EventName.pwa_conv_location_page_confirm, { zipcode: zipCode }); // 转化埋点

        goBack(navigate);
      } catch (e) {
        console.error("Failed to save location:", e);
        toast.error("Failed to save location, please try again");
      }
    },
    [updateProfile, finishTask, navigate],
  );

  // 有经纬度参数时自动反解地址并保存
  useEffect(() => {
    if (!state?.lat || !state?.lng) return;

    const handleLatLng = async () => {
      showLoading();
      try {
        const { zipcode: resolvedZip, city, state: resolvedState } = await getGeocodeInfo(state.lat!, state.lng!);
        if (resolvedZip && resolvedZip.trim() !== "") {
          setZipcode(resolvedZip);
          await handleSave(resolvedState ?? "", city ?? "", resolvedZip);
        } else {
          // 反解失败，提示用户手动输入
          toast.error("Unable to detect your zipcode automatically. Please enter it manually.");
          // 自动 focus 输入框
          setTimeout(() => inputRef.current?.focus(), 100);
        }
      } catch (e) {
        console.error("Failed to resolve location:", e);
        toast.error("Unable to detect your zipcode automatically. Please enter it manually.");
        // 自动 focus 输入框
        setTimeout(() => inputRef.current?.focus(), 100);
      } finally {
        hideLoading();
      }
    };

    handleLatLng();
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const handleChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const value = event.target.value;
    setError(false);
    setZipcode(value);
    const match = csvData.find((row) => row.usZipcode === value);
    setHint(match ? match.location : DEFAULT_HINT);
  };

  const handleNext = async () => {
    if (!isValidZipCode(zipcode)) {
      setError(true);
      setHint(ERROR_HINT);
      return;
    }

    showLoading();
    try {
      let province = "";
      let city = "";
      const match = csvData.find((row) => row.usZipcode === zipcode);
      if (match) {
        const parts = match.location.split(",");
        city = parts[0]?.trim() ?? "";
        province = parts[1]?.trim() ?? "";
      }
      await handleSave(province, city, zipcode);
    } finally {
      hideLoading();
    }
  };

  const isDisabled = error || zipcode === "";

  return (
    <div className="flex flex-col w-full h-full animate-fade-in bg-surface">
      <NavigationBar />

      <div className="flex-1 flex flex-col p-6">
        <Input
          ref={inputRef}
          title="What's Your Zipcode?"
          titleClassName="text-xl font-bold capitalize text-brand-dark"
          error={error ? hint : null}
          hint={<p className="text-[#159CD7] text-xs font-medium text-center">{hint}</p>}
          inputProps={{
            type: "text",
            autoComplete: "off",
            inputMode: "numeric",
            value: zipcode,
            onChange: handleChange,
            placeholder: "example: 75231",
          }}
        />

        <Button onClick={handleNext} disabled={isDisabled} variant="primary" className="shrink-0">
          Next
        </Button>
      </div>
    </div>
  );
}
